import fs from "fs";
import path from "path";

const root = path.resolve(import.meta.dirname, "..");

const files = [
  { exportName: "shapeLandingHeroCode", file: "components/ui/shape-landing-hero.tsx" },
  { exportName: "gridGlowBackgroundCode", file: "components/ui/grid-glow-background.tsx" },
  { exportName: "tubeCursorCode", file: "components/ui/tube-cursor.tsx" },
];

function escapeTemplateLiteral(s) {
  return s.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/\$\{/g, "\\${");
}

const parts = [
  "// Auto-generated by scripts/generate-component-code-snippets.mjs — do not edit by hand",
  "",
];

for (const { exportName, file } of files) {
  const raw = fs.readFileSync(path.join(root, file), "utf8");
  parts.push(`export const ${exportName} = \`${escapeTemplateLiteral(raw)}\`;`);
  parts.push("");
}

fs.writeFileSync(path.join(root, "lib/component-code-snippets.ts"), parts.join("\n"), "utf8");
console.log("Wrote lib/component-code-snippets.ts");
